@classmethod
def from_series(
    cls, row: pd.Series, markers: Dict[str, Dict[str, List[str]]]
) -> "Persona":
    """Construct a Persona from a synthetic_personas.csv row.

    Expects columns including persona_id, demographics, BFI_*, NFC_Total,
    and CRT2_Total_adj / CRT_Combined.
    """
    if "persona_id" not in row:
        raise ValueError("Personas dataframe must include 'persona_id' column.")
    persona_id = str(row["persona_id"])

    # Build demographics from the specified columns only
    demo_cols = [
        "Country",
        "Employment Status",
        "Occupation_cat",
        "sex",
        "Highest education level completed",
        "Ethnicity Simplified",
        "Age",
    ]
    demographics = {k: row[k] for k in demo_cols if k in row.index}

    # Map trait columns to internal names
    traits: Dict[str, float] = {}
    bfi_map = {
        "BFI_Extraversion": "bfi_extraversion",
        "BFI_Agreeableness": "bfi_agreeableness",
        "BFI_Conscientiousness": "bfi_conscientiousness",
        "BFI_Neuroticism": "bfi_neuroticism",
        "BFI_Openness": "bfi_openness",
    }
    for src, dst in bfi_map.items():
        if src in row.index:
            traits[dst] = float(row[src])

    if "NFC_Total" in row.index:
        traits["nfc_score"] = float(row["NFC_Total"])

    # Choose a CRT anchor; here we use CRT2_Total_adj but could use CRT_Combined
    if "CRT2_Total_adj" in row.index:
        traits["crt2_score"] = float(row["CRT2_Total_adj"])

    return cls(
        persona_id=persona_id,
        demographics=demographics,
        traits=traits,
        markers=markers,
    )
